-- =====================================================
-- 2. Структурированные критерии перехода shoulder_ac_conservative
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фазы 0/prehab НЕТ (консервативный трек). Фазы 1–3 (терминальная 3 несёт критерии возврата).
--    measurement = боль ВАШ (vas_score+pain) ТОЛЬКО; объём/градусы/% силы → instructor_check.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (защита и ранние движения → восстановление амплитуды)
  (1, 'pain_rest_min_p1',        'Боль в покое и при обычных бытовых движениях минимальна (не более 3 из 10)',                'measurement',      'vas_score'::varchar, 'pain'::varchar, '<='::varchar, 3::numeric, NULL::numeric, 7::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'sling_off_waist_p1',      'Можете снять косынку и пользоваться рукой на уровне пояса без выраженной боли',              'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете снять косынку и пользоваться рукой на уровне пояса без выраженной боли?', 'Например: одеться, поесть, взять предмет с полки на уровне пояса', 20::smallint, TRUE),
  (1, 'assisted_flexion_90_p1',  'Подъём руки вперёд при поддержке достигает 90°',                                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'no_guarding_p1',          'Нет выраженного мышечного «сторожевого» спазма, упражнения на лопатку с опорой даются без боли', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (1, 'no_deformity_progress_p1','Нет нарастания деформации или нестабильности (нет перехода в более тяжёлую степень)',        'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),

  -- Фаза 2 → Фаза 3 (восстановление амплитуды → продвинутое укрепление)
  (2, 'active_flexion_160_p2',   'Активный подъём руки вперёд не менее 160–170° (полная или близкая к полной безболезненная амплитуда)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'strength_70pct_p2',       'Сила больной стороны (дельтовидная, трапециевидная, ротаторы) не менее 70% от здоровой руки', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'pain_overhead_gone_p2',   'Полностью прошла боль при обычных движениях рукой, включая над головой',                     'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Полностью ли прошла боль при обычных движениях рукой, включая над головой?', 'Оцените подъём руки вперёд, в сторону и над головой', 30::smallint, TRUE),
  (2, 'scapular_rhythm_p2',      'Восстановлена слаженная работа лопатки, нет болезненной дуги при подъёме руки в сторону',    'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'no_ac_palpation_pain_p2', 'Нет болезненности при ощупывании акромиально-ключичного сустава в покое',                    'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 3 (терминальная) — критерии выписки / возврата к активности и спорту
  (3, 'strength_75pct_p3',       'Сила больной стороны не менее 75% от здоровой руки (для контактного спорта и работы над головой ориентир ближе к 90%)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'full_painfree_rom_p3',    'Полная безболезненная амплитуда во всех направлениях (в пределах примерно 5° от здоровой стороны)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'shoulder_reliable_p3',    'Чувствуете плечо надёжным при нагрузке и готовы вернуться к спорту',                         'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Чувствуете плечо надёжным и уверенным при нагрузке, готовы вернуться к спорту?', 'Оцените уверенность при привычных нагрузочных движениях', 30::smallint, TRUE),
  (3, 'sleep_affected_side_p3',  'Можете спать на больной стороне без пробуждений от боли',                                    'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете спать на больной стороне без пробуждений от боли?', 'Оцените сон за последнюю неделю', 40::smallint, TRUE),
  (3, 'provocative_tests_ok_p3', 'Нет болезненности сустава при ощупывании; приведение руки через тело и потягивание руки без боли', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),
  (3, 'sport_test_passed_p3',    'Слаженная работа плеча и лопатки при нагрузках без нарушений; спорт-специфический тест пройден', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 60::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_ac_conservative' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
